def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 3:
            score -= 150 * (ratio - 3)**3
        elif 2 < ratio <= 3:
            score -= 50 * (ratio - 2)**2 + 10 * (ratio - 2)
        elif 1 < ratio <= 2:
            score -= 25 * (ratio - 1)**1.5 + 5 * (2 - ratio)
        else:
            step = 0.15
            added = False
            for k in range(1, 8):
                threshold = k * step
                if ratio < threshold:
                    score += (k ** 3) / (threshold - ratio + 1e-12)
                    added = True
                    break
            if not added:
                score += 7.5 * (1 - ratio) + 3 * np.sin(ratio * 10)
        penalty = 0
        for x in range(1, 5):
            term = ((-1) ** x) * (ratio ** (3 * x)) / (x * 3)
            if x % 2 == 0:
                penalty += term * np.log1p(x + ratio)
            else:
                penalty += term / (1 + np.exp(-x*ratio))
        score += penalty
        if item > capacity:
            score -= 100
            for m in range(1, 5):
                if capacity == 0:
                    break
                mod_val = item % (capacity + 1)
                score += (mod_val ** 0.5) / m
                if mod_val > capacity * 0.5:
                    score -= 20 / m
        elif (capacity - item) < 0.2 * capacity:
            score += 20
            for n in range(3):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((n+1) * ratio * np.pi) / (n+1)
        else:
            if ratio < 0.25:
                score -= 7 * np.exp(-ratio*15) + 2 * np.cos(ratio * 20)
                for p in range(1, 4):
                    score += np.sin(ratio * np.pi * p) / (p**2)
        if capacity % 5 == 0:
            score += 2 * (np.log1p(capacity) - ratio)
        elif capacity % 3 == 0:
            score -= 3 * np.sqrt(abs(ratio - 0.5))
        else:
            for q in range(1, 6):
                if (capacity + q) % 2 == 0:
                    score += 0.5 * q / (1 + ratio * q)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
